/**
 * Shared game constants and types.
 *
 * Single source of truth for values that must match between
 * the client game (index.ts HTML) and the server replay engine.
 */
declare const XP_PER_WORD = 100;
type GuessedInput = {
    round: number;
    guess: string;
};
type GuessedGameConfig = {
    words: string[];
    maxGuesses: number;
    timeLimit: number;
};
type GuessedReplayResult = {
    score: number;
    roundResults: {
        word: string;
        guessed: boolean;
    }[];
};

